// ============================================
// SUPPLIER & PURCHASE ORDER TYPES
// ============================================

interface Supplier {
  id: string
  code: string
  name: string
  contactPerson: string
  email: string
  phone: string
  address: string
  city: string
  country: string
  specialty: string
  paymentTerms: string
  deliveryDays: number
  minOrderAmount: number
  rating: number // 1-5
  status: 'active' | 'inactive'
  totalOrders: number
  lastOrderDate?: string
  notes?: string
}

interface PurchaseOrder {
  id: string
  orderNumber: string
  supplierId: string
  supplierName: string
  items: { productId: string; productName: string; quantity: number; unitPrice: number; total: number }[]
  subtotal: number
  tax: number
  total: number
  status: 'draft' | 'sent' | 'confirmed' | 'partial_received' | 'received' | 'cancelled'
  orderDate: string
  expectedDeliveryDate?: string
  receivedDate?: string
  notes?: string
  createdBy: string
}

// ============================================
// PAYMENT & REMINDER TYPES
// ============================================

interface Payment {
  id: string
  paymentNumber: string
  orderId: string
  orderNumber: string
  clientId: string
  clientName: string
  amount: number
  method: 'cash' | 'bank_transfer' | 'check' | 'mobile_money'
  reference?: string
  notes?: string
  status: 'pending' | 'confirmed' | 'cancelled'
  paidAt: string
  recordedBy: string
}

interface ClientReminder {
  id: string
  clientId: string
  clientName: string
  invoiceId: string
  invoiceNumber: string
  amountDue: number
  daysOverdue: number
  level: 1 | 2 | 3
  status: 'pending' | 'sent' | 'acknowledged'
  sentAt?: string
  notes?: string
}

interface SalesTarget {
  id: string
  dmId: string
  dmName: string
  period: 'monthly' | 'quarterly'
  month: string
  year: number
  targetRevenue: number
  targetOrders: number
  targetNewClients: number
  achievedRevenue: number
  achievedOrders: number
  achievedNewClients: number
  status: 'in_progress' | 'achieved' | 'exceeded' | 'failed'
}

// Inventaire Physique
interface InventoryCount {
  id: string
  countNumber: string
  name: string
  status: 'draft' | 'in_progress' | 'completed' | 'validated'
  createdAt: string
  createdBy: string
  startedAt?: string
  completedAt?: string
  validatedAt?: string
  validatedBy?: string
  notes?: string
  items: InventoryCountItem[]
}

interface InventoryCountItem {
  id: string
  productId: string
  productName: string
  productCode: string
  location: string
  theoreticalQty: number
  countedQty: number | null
  variance: number
  variancePercent: number
  status: 'pending' | 'counted' | 'verified'
  countedBy?: string
  countedAt?: string
  notes?: string
}

interface InventoryVariance {
  id: string
  inventoryCountId: string
  productId: string
  productName: string
  variance: number
  reason: 'damage' | 'theft' | 'expired' | 'counting_error' | 'system_error' | 'other'
  notes?: string
  adjustmentValue: number
  approvedBy?: string
  approvedAt?: string
}

