                      <thead className="bg-muted/50">
                        <tr>
                          <th className="text-left p-4 font-medium">Produit</th>
                          <th className="text-left p-4 font-medium">Écart</th>
                          <th className="text-left p-4 font-medium">Motif</th>
                          <th className="text-left p-4 font-medium">Valeur</th>
                          <th className="text-left p-4 font-medium">Approuvé par</th>
                        </tr>
                      </thead>
