// Dashboard Principal - Route vers le bon dashboard selon le rôle
function DashboardModule({ user }: { user: UserType }) {
  const today = new Date()
  const dateStr = today.toLocaleDateString('fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })

  const getGreeting = () => {
    const hour = today.getHours()
    if (hour < 12) return 'Bonjour'
    if (hour < 18) return 'Bon après-midi'
    return 'Bonsoir'
  }

  const renderDashboardByRole = () => {
    switch (user.role) {
      case 'dm':
        return <DMDashboard user={user} />
      case 'superviseur':
        return <SupervisorDashboard user={user} />
      case 'comptabilite':
        return <AccountingDashboard />
      case 'marketing':
        return <MarketingDashboard />
      case 'admin':
        return <AdminDashboard />
      default:
        return <DMDashboard user={user} />
    }
  }

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={staggerContainer}
      className="space-y-6"
    >
      {/* Header */}
      <motion.div variants={fadeInUp} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold">{getGreeting()}, {user.name.split(' ')[0]} 👋</h1>
          <p className="text-muted-foreground mt-1 capitalize">{dateStr}</p>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant="outline" className="gap-1">
            <MapPin className="h-3 w-3" />{user.region || 'Siège'}
          </Badge>
          <Badge className="gap-1 bg-gradient-to-r from-blue-500 to-purple-500">
            {roleLabels[user.role]}
          </Badge>
        </div>
      </motion.div>

      {/* Dashboard spécifique au rôle */}
      {renderDashboardByRole()}
    </motion.div>
  )
}

