// ============================================
// BUDGET MODULE
// ============================================

function BudgetModule({ user }: { user: UserType }) {
  const [budgetList, setBudgetList] = useState<Budget[]>(budgets)
  const [selectedBudget, setSelectedBudget] = useState<Budget | null>(null)
  const [showBudgetForm, setShowBudgetForm] = useState(false)
  const [editingBudget, setEditingBudget] = useState<Budget | null>(null)
  const { toast } = useToast()

  // Filtrer les budgets selon le rôle
  const getAccessibleBudgets = () => {
    if (user.role === 'admin') {
      return budgetList
    } else if (user.role === 'comptabilite') {
      return budgetList.filter(b => b.status === 'submitted' || b.status === 'approved' || b.status === 'rejected')
    } else if (user.role === 'superviseur') {
      return budgetList.filter(b => b.supervisorName === user.name)
    } else if (user.role === 'dm') {
      // DM voit les budgets validés de son superviseur
      const mySupervisor = demoDMs.find(dm => dm.name === user.name)?.assignedSupervisor
      return budgetList.filter(b => b.supervisorName === mySupervisor && b.status === 'approved')
    }
    return []
  }

  const accessibleBudgets = getAccessibleBudgets()

  const canCreateBudget = () => user.role === 'superviseur'
  const canEditBudget = (budget: Budget) => user.role === 'superviseur' && budget.supervisorName === user.name && budget.status === 'draft'
  const canValidateBudget = () => user.role === 'comptabilite'
  const canViewBudget = () => user.role === 'dm' || user.role === 'superviseur' || user.role === 'comptabilite' || user.role === 'admin'

  const handleSaveBudget = (budgetData: Partial<Budget>) => {
    if (editingBudget) {
      setBudgetList(budgetList.map(b => b.id === editingBudget.id ? { ...b, ...budgetData } : b))
      toast({ title: 'Budget modifié', description: 'Le budget a été mis à jour' })
    } else {
      const newBudget: Budget = {
        id: 'b' + Date.now(),
        supervisorId: 'sup1',
        supervisorName: user.name,
        region: user.region || 'Douala',
        month: budgetData.month || 'Mars',
        year: 2025,
        categories: budgetData.categories || { carburant: 0, hebergement: 0, repas: 0, transport: 0, autres: 0 },
        total: budgetData.total || 0,
        status: 'draft'
      }
      setBudgetList([newBudget, ...budgetList])
      toast({ title: 'Budget créé', description: 'Le budget a été créé en brouillon' })
    }
    setShowBudgetForm(false)
    setEditingBudget(null)
  }

  const handleSubmitBudget = (budget: Budget) => {
    setBudgetList(budgetList.map(b => b.id === budget.id ? { ...b, status: 'submitted', submittedAt: new Date().toISOString().split('T')[0] } : b))
    toast({ title: 'Budget soumis', description: 'Le budget a été soumis à validation' })
    setSelectedBudget(null)
  }

  const handleValidateBudget = (budget: Budget, approved: boolean, comment?: string) => {
    setBudgetList(budgetList.map(b => b.id === budget.id ? {
      ...b,
      status: approved ? 'approved' : 'rejected',
      reviewedAt: new Date().toISOString().split('T')[0],
      reviewedBy: 'Service Comptabilité',
      comment
    } : b))
    toast({
      title: approved ? 'Budget approuvé' : 'Budget rejeté',
      description: approved ? 'Le budget a été approuvé' : 'Le budget a été rejeté'
    })
    setSelectedBudget(null)
  }

  const budgetStatusColors = {
    draft: 'bg-gray-100 text-gray-800',
    submitted: 'bg-blue-100 text-blue-800',
    approved: 'bg-green-100 text-green-800',
    rejected: 'bg-red-100 text-red-800'
  }

  const budgetStatusLabels = {
    draft: 'Brouillon',
    submitted: 'Soumis',
    approved: 'Approuvé',
    rejected: 'Rejeté'
  }

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={staggerContainer}
      className="space-y-6"
    >
      <motion.div variants={fadeInUp} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">Gestion des Budgets</h1>
          <p className="text-muted-foreground">
            {user.role === 'dm' ? 'Budgets de votre équipe' :
             user.role === 'superviseur' ? 'Vos budgets régionaux' :
             user.role === 'comptabilite' ? 'Validation des budgets' :
             'Tous les budgets'}
          </p>
        </div>
        {canCreateBudget() && (
          <Button onClick={() => { setEditingBudget(null); setShowBudgetForm(true) }} className="gap-2">
            <Plus className="h-4 w-4" />Nouveau budget
          </Button>
        )}
      </motion.div>

      {/* Info banner */}
      {user.role === 'dm' && (
        <motion.div variants={fadeIn}>
          <Card className="bg-blue-50 dark:bg-blue-900/20 border-blue-200">
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <DollarSign className="h-5 w-5 text-blue-600" />
                <p className="text-sm text-blue-800 dark:text-blue-200">
                  Vous consultez les budgets validés de votre superviseur.
                </p>
              </div>
            </CardContent>
          </Card>
        </motion.div>
      )}

      {/* Stats */}
      <motion.div variants={staggerContainer} className="grid grid-cols-1 sm:grid-cols-4 gap-4">
        {[
          { value: accessibleBudgets.filter(b => b.status === 'approved').length.toString(), label: 'Approuvés', color: 'text-green-600' },
          { value: accessibleBudgets.filter(b => b.status === 'submitted').length.toString(), label: 'En attente', color: 'text-blue-600' },
          { value: accessibleBudgets.filter(b => b.status === 'draft').length.toString(), label: 'Brouillons', color: 'text-gray-600' },
          { value: accessibleBudgets.filter(b => b.status === 'approved').reduce((sum, b) => sum + b.total, 0).toLocaleString() + ' XAF', label: 'Total approuvé', color: 'text-purple-600' },
        ].map((stat, i) => (
          <Card key={i}>
            <CardContent className="p-4 text-center">
              <p className={`text-2xl font-bold ${stat.color}`}><AnimatedCounter value={stat.value.replace(' XAF', '')} />{stat.value.includes('XAF') ? ' XAF' : ''}</p>
              <p className="text-sm text-muted-foreground">{stat.label}</p>
            </CardContent>
          </Card>
        ))}
      </motion.div>

      {/* Budget list */}
      <motion.div variants={fadeInUp}>
        <Card>
          <CardHeader>
            <CardTitle>Liste des budgets</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr>
                    <th className="text-left p-4 font-medium">Superviseur</th>
                    <th className="text-left p-4 font-medium">Région</th>
                    <th className="text-left p-4 font-medium">Mois</th>
                    <th className="text-left p-4 font-medium">Total</th>
                    <th className="text-left p-4 font-medium">Statut</th>
                    <th className="text-left p-4 font-medium">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {accessibleBudgets.map((budget, i) => (
                    <motion.tr
                      key={budget.id}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: i * 0.05 }}
                      onClick={() => setSelectedBudget(budget)}
                      className="border-t cursor-pointer hover:bg-muted/50"
                    >
                      <td className="p-4 font-medium">{budget.supervisorName}</td>
                      <td className="p-4">{budget.region}</td>
                      <td className="p-4">{budget.month} {budget.year}</td>
                      <td className="p-4 font-medium">{budget.total.toLocaleString()} XAF</td>
                      <td className="p-4">
                        <Badge className={budgetStatusColors[budget.status]}>{budgetStatusLabels[budget.status]}</Badge>
                      </td>
                      <td className="p-4">
                        <div className="flex gap-1" onClick={(e) => e.stopPropagation()}>
                          <Button variant="ghost" size="icon" onClick={() => setSelectedBudget(budget)}>
                            <ViewIcon className="h-4 w-4" />
                          </Button>
                          {canEditBudget(budget) && (
                            <Button variant="ghost" size="icon" onClick={() => { setEditingBudget(budget); setShowBudgetForm(true) }}>
                              <Edit className="h-4 w-4" />
                            </Button>
                          )}
                        </div>
                      </td>
                    </motion.tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </motion.div>

      {/* Budget Detail Modal */}
      <AnimatePresence>
        {selectedBudget && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
            onClick={() => setSelectedBudget(null)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
              className="bg-card rounded-xl w-full max-w-lg shadow-2xl"
            >
              <div className="p-4 bg-primary text-white rounded-t-xl">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="font-bold text-lg">Budget {selectedBudget.month} {selectedBudget.year}</h3>
                    <p className="text-white/80 text-sm">{selectedBudget.supervisorName} - {selectedBudget.region}</p>
                  </div>
                  <Button variant="ghost" size="icon" onClick={() => setSelectedBudget(null)} className="text-white hover:bg-white/20">
                    <X className="h-5 w-5" />
                  </Button>
                </div>
              </div>

              <div className="p-6 space-y-4">
                <div className="space-y-3">
                  {[
                    { label: 'Carburant', value: selectedBudget.categories.carburant },
                    { label: 'Hébergement', value: selectedBudget.categories.hebergement },
                    { label: 'Repas', value: selectedBudget.categories.repas },
                    { label: 'Transport', value: selectedBudget.categories.transport },
                    { label: 'Autres', value: selectedBudget.categories.autres },
                  ].map((cat, i) => (
                    <div key={i} className="flex justify-between items-center">
                      <span className="text-muted-foreground">{cat.label}</span>
                      <span className="font-medium">{cat.value.toLocaleString()} XAF</span>
                    </div>
                  ))}
                </div>

                <Separator />

                <div className="flex justify-between items-center text-lg">
                  <span className="font-bold">Total</span>
                  <span className="font-bold text-primary">{selectedBudget.total.toLocaleString()} XAF</span>
                </div>

                <div className="text-sm text-muted-foreground">
                  <Badge className={budgetStatusColors[selectedBudget.status]}>{budgetStatusLabels[selectedBudget.status]}</Badge>
                  {selectedBudget.submittedAt && <span className="ml-2">Soumis le {selectedBudget.submittedAt}</span>}
                </div>

                {selectedBudget.comment && (
                  <div className="p-3 bg-muted rounded-lg text-sm">
                    <p className="font-medium">Commentaire:</p>
                    <p className="text-muted-foreground">{selectedBudget.comment}</p>
                  </div>
                )}

                {/* Actions */}
                <div className="flex gap-2 pt-2">
                  {user.role === 'superviseur' && selectedBudget.supervisorName === user.name && selectedBudget.status === 'draft' && (
                    <Button onClick={() => handleSubmitBudget(selectedBudget)} className="flex-1 gap-2">
                      <Send className="h-4 w-4" />Soumettre
                    </Button>
                  )}
                  {canValidateBudget() && selectedBudget.status === 'submitted' && (
                    <>
                      <Button onClick={() => handleValidateBudget(selectedBudget, true)} className="flex-1 gap-2 bg-green-600 hover:bg-green-700">
                        <Check className="h-4 w-4" />Approuver
                      </Button>
                      <Button onClick={() => handleValidateBudget(selectedBudget, false)} variant="destructive" className="flex-1 gap-2">
                        <X className="h-4 w-4" />Rejeter
                      </Button>
                    </>
                  )}
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <Toaster />
    </motion.div>
  )
}

// ============================================
// ACTIVITY REPORTS MODULE
// ============================================

function ActivityReportsModule({ user }: { user: UserType }) {
  const [reports, setReports] = useState<ActivityReport[]>(activityReports)
  const [selectedReport, setSelectedReport] = useState<ActivityReport | null>(null)
  const [showReportForm, setShowReportForm] = useState(false)
  const { toast } = useToast()

  // Filtrer les rapports selon le rôle
  const getAccessibleReports = () => {
    if (user.role === 'admin') {
      return reports
    } else if (user.role === 'superviseur') {
      return reports.filter(r => r.supervisorName === user.name)
    }
    return []
  }

  const accessibleReports = getAccessibleReports()

  const canCreateReport = () => user.role === 'superviseur'

  const handleSaveReport = (reportData: Partial<ActivityReport>, type: 'weekly' | 'monthly') => {
    const today = new Date()
    const startDate = type === 'weekly' 
      ? new Date(today.setDate(today.getDate() - 7)).toISOString().split('T')[0]
      : new Date(today.getFullYear(), today.getMonth(), 1).toISOString().split('T')[0]
    
    const newReport: ActivityReport = {
      id: 'ar' + Date.now(),
      supervisorId: 'sup1',
      supervisorName: user.name,
      type,
      startDate: reportData.startDate || startDate,
      endDate: reportData.endDate || new Date().toISOString().split('T')[0],
      summary: reportData.summary || '',
      visitsCompleted: reportData.visitsCompleted || 0,
      visitsPlanned: reportData.visitsPlanned || 0,
      teamPerformance: reportData.teamPerformance || 0,
      challenges: reportData.challenges || '',
      recommendations: reportData.recommendations || '',
      status: 'submitted',
      createdAt: new Date().toISOString().split('T')[0]
    }
    setReports([newReport, ...reports])
    setShowReportForm(false)
    toast({ title: 'Rapport soumis', description: `Rapport ${type === 'weekly' ? 'hebdomadaire' : 'mensuel'} soumis avec succès` })
  }

  const typeLabels = {
    weekly: 'Hebdomadaire',
    monthly: 'Mensuel'
  }

  const typeColors = {
    weekly: 'bg-blue-100 text-blue-800',
    monthly: 'bg-purple-100 text-purple-800'
  }

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={staggerContainer}
      className="space-y-6"
    >
      <motion.div variants={fadeInUp} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">Rapports d'Activité</h1>
          <p className="text-muted-foreground">
            {user.role === 'admin' ? 'Rapports des superviseurs' : 'Vos rapports d\'activité'}
          </p>
        </div>
        {canCreateReport() && (
          <Button onClick={() => setShowReportForm(true)} className="gap-2">
            <Plus className="h-4 w-4" />Nouveau rapport
          </Button>
        )}
      </motion.div>

      {/* Info banner */}
      {user.role === 'superviseur' && (
        <motion.div variants={fadeIn}>
          <Card className="bg-amber-50 dark:bg-amber-900/20 border-amber-200">
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <FileText className="h-5 w-5 text-amber-600" />
                <p className="text-sm text-amber-800 dark:text-amber-200">
                  Vos rapports sont consultables par le super-administrateur.
                </p>
              </div>
            </CardContent>
          </Card>
        </motion.div>
      )}

      {/* Stats */}
      <motion.div variants={staggerContainer} className="grid grid-cols-1 sm:grid-cols-4 gap-4">
        {[
          { value: accessibleReports.filter(r => r.type === 'weekly').length.toString(), label: 'Hebdomadaires', color: 'text-blue-600' },
          { value: accessibleReports.filter(r => r.type === 'monthly').length.toString(), label: 'Mensuels', color: 'text-purple-600' },
          { value: accessibleReports.reduce((sum, r) => sum + r.visitsCompleted, 0).toString(), label: 'Visites totales', color: 'text-green-600' },
          { value: Math.round(accessibleReports.reduce((sum, r) => sum + r.teamPerformance, 0) / (accessibleReports.length || 1)) + '%', label: 'Performance moyenne', color: 'text-amber-600' },
        ].map((stat, i) => (
          <Card key={i}>
            <CardContent className="p-4 text-center">
              <p className={`text-2xl font-bold ${stat.color}`}><AnimatedCounter value={stat.value} /></p>
              <p className="text-sm text-muted-foreground">{stat.label}</p>
            </CardContent>
          </Card>
        ))}
      </motion.div>

      {/* Reports list */}
      <motion.div variants={fadeInUp}>
        <Card>
          <CardHeader>
            <CardTitle>Historique des rapports</CardTitle>
          </CardHeader>
          <CardContent className="p-0">
            {accessibleReports.length === 0 ? (
              <div className="text-center py-12 text-muted-foreground">
                <FileText className="h-12 w-12 mx-auto mb-4 opacity-50" />
                <p>Aucun rapport disponible</p>
              </div>
            ) : (
              <div className="divide-y">
                {accessibleReports.map((report, i) => (
                  <motion.div
                    key={report.id}
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: i * 0.05 }}
                    onClick={() => setSelectedReport(report)}
                    className="p-4 hover:bg-muted/50 cursor-pointer transition-colors"
                  >
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <Badge className={typeColors[report.type]}>{typeLabels[report.type]}</Badge>
                          <span className="text-sm text-muted-foreground">{report.startDate} → {report.endDate}</span>
                        </div>
                        <p className="text-sm line-clamp-2 mt-2">{report.summary}</p>
                        <div className="flex items-center gap-4 mt-2 text-xs text-muted-foreground">
                          <span>{report.visitsCompleted}/{report.visitsPlanned} visites</span>
                          <span>Performance: {report.teamPerformance}%</span>
                          {user.role === 'admin' && <span>Par: {report.supervisorName}</span>}
                        </div>
                      </div>
                      <ChevronRight className="h-5 w-5 text-muted-foreground" />
                    </div>
                  </motion.div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </motion.div>

      {/* Report Detail Modal */}
      <AnimatePresence>
        {selectedReport && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
            onClick={() => setSelectedReport(null)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
              className="bg-card rounded-xl w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto"
            >
              <div className={`p-4 ${selectedReport.type === 'weekly' ? 'bg-blue-500' : 'bg-purple-500'} text-white rounded-t-xl`}>
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="font-bold text-lg">Rapport {typeLabels[selectedReport.type]}</h3>
                    <p className="text-white/80 text-sm">{selectedReport.startDate} → {selectedReport.endDate}</p>
                  </div>
                  <Button variant="ghost" size="icon" onClick={() => setSelectedReport(null)} className="text-white hover:bg-white/20">
                    <X className="h-5 w-5" />
                  </Button>
                </div>
              </div>

              <div className="p-6 space-y-6">
                <div>
                  <p className="text-sm text-muted-foreground mb-2">Résumé</p>
                  <p>{selectedReport.summary}</p>
                </div>

                <div className="grid grid-cols-3 gap-4">
                  <div className="text-center p-4 bg-muted rounded-lg">
                    <p className="text-2xl font-bold text-green-600">{selectedReport.visitsCompleted}</p>
                    <p className="text-sm text-muted-foreground">Visites complétées</p>
                  </div>
                  <div className="text-center p-4 bg-muted rounded-lg">
                    <p className="text-2xl font-bold text-blue-600">{selectedReport.visitsPlanned}</p>
                    <p className="text-sm text-muted-foreground">Visites planifiées</p>
                  </div>
                  <div className="text-center p-4 bg-muted rounded-lg">
                    <p className="text-2xl font-bold text-purple-600">{selectedReport.teamPerformance}%</p>
                    <p className="text-sm text-muted-foreground">Performance</p>
                  </div>
                </div>

                <div>
                  <p className="text-sm text-muted-foreground mb-2">Défis rencontrés</p>
                  <div className="p-3 bg-red-50 dark:bg-red-900/20 rounded-lg">
                    <p className="text-sm">{selectedReport.challenges}</p>
                  </div>
                </div>

                <div>
                  <p className="text-sm text-muted-foreground mb-2">Recommandations</p>
                  <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-lg">
                    <p className="text-sm">{selectedReport.recommendations}</p>
                  </div>
                </div>

                {user.role === 'admin' && (
                  <div className="pt-2 border-t text-sm text-muted-foreground">
                    <p>Superviseur: <span className="font-medium">{selectedReport.supervisorName}</span></p>
                    <p>Soumis le: <span className="font-medium">{selectedReport.createdAt}</span></p>
                  </div>
                )}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* New Report Form Modal */}
      <AnimatePresence>
        {showReportForm && (
          <NewActivityReportModal
            user={user}
            onSave={handleSaveReport}
            onClose={() => setShowReportForm(false)}
          />
        )}
      </AnimatePresence>

      <Toaster />
    </motion.div>
  )
}

// ============================================
// NEW ACTIVITY REPORT MODAL
// ============================================

function NewActivityReportModal({
  user,
  onSave,
  onClose
}: {
  user: UserType
  onSave: (data: Partial<ActivityReport>, type: 'weekly' | 'monthly') => void
  onClose: () => void
}) {
  const [reportType, setReportType] = useState<'weekly' | 'monthly'>('weekly')
  const [form, setForm] = useState({
    summary: '',
    visitsCompleted: 0,
    visitsPlanned: 0,
    challenges: '',
    recommendations: ''
  })

  // Calculer la performance
  const teamPerformance = form.visitsPlanned > 0 
    ? Math.round((form.visitsCompleted / form.visitsPlanned) * 100) 
    : 0

  const handleSubmit = () => {
    if (!form.summary) return
    onSave({ ...form, teamPerformance }, reportType)
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.9, opacity: 0 }}
        onClick={(e) => e.stopPropagation()}
        className="bg-card rounded-xl w-full max-w-lg shadow-2xl max-h-[90vh] overflow-y-auto"
      >
        <div className="p-6 border-b">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold">Nouveau Rapport d'Activité</h2>
            <Button variant="ghost" size="icon" onClick={onClose}>
              <X className="h-5 w-5" />
            </Button>
          </div>
        </div>

        <div className="p-6 space-y-6">
          {/* Type de rapport */}
          <div className="space-y-2">
            <Label>Type de rapport</Label>
            <div className="flex gap-3">
              <button
                onClick={() => setReportType('weekly')}
                className={`flex-1 p-3 rounded-lg border-2 transition-all ${
                  reportType === 'weekly' ? 'bg-blue-100 border-blue-300 text-blue-800' : 'bg-background border-muted'
                }`}
              >
                <p className="font-medium">Hebdomadaire</p>
              </button>
              <button
                onClick={() => setReportType('monthly')}
                className={`flex-1 p-3 rounded-lg border-2 transition-all ${
                  reportType === 'monthly' ? 'bg-purple-100 border-purple-300 text-purple-800' : 'bg-background border-muted'
                }`}
              >
                <p className="font-medium">Mensuel</p>
              </button>
            </div>
          </div>

          {/* Résumé */}
          <div className="space-y-2">
            <Label>Résumé des activités *</Label>
            <textarea
              value={form.summary}
              onChange={(e) => setForm({ ...form, summary: e.target.value })}
              placeholder="Décrivez les principales activités réalisées..."
              className="w-full border rounded-lg px-3 py-2 bg-background min-h-[80px] resize-y"
            />
          </div>

          {/* Statistiques */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Visites complétées</Label>
              <Input
                type="number"
                value={form.visitsCompleted}
                onChange={(e) => setForm({ ...form, visitsCompleted: parseInt(e.target.value) || 0 })}
              />
            </div>
            <div className="space-y-2">
              <Label>Visites planifiées</Label>
              <Input
                type="number"
                value={form.visitsPlanned}
                onChange={(e) => setForm({ ...form, visitsPlanned: parseInt(e.target.value) || 0 })}
              />
            </div>
          </div>

          <div className="p-4 bg-muted rounded-lg text-center">
            <p className="text-sm text-muted-foreground">Performance calculée</p>
            <p className="text-3xl font-bold text-primary">{teamPerformance}%</p>
          </div>

          {/* Défis */}
          <div className="space-y-2">
            <Label>Défis rencontrés</Label>
            <textarea
              value={form.challenges}
              onChange={(e) => setForm({ ...form, challenges: e.target.value })}
              placeholder="Difficultés, obstacles, problèmes rencontrés..."
              className="w-full border rounded-lg px-3 py-2 bg-background min-h-[60px] resize-y"
            />
          </div>

          {/* Recommandations */}
          <div className="space-y-2">
            <Label>Recommandations</Label>
            <textarea
              value={form.recommendations}
              onChange={(e) => setForm({ ...form, recommendations: e.target.value })}
              placeholder="Propositions d'amélioration..."
              className="w-full border rounded-lg px-3 py-2 bg-background min-h-[60px] resize-y"
            />
          </div>
        </div>

        <div className="p-6 border-t flex gap-3">
          <Button onClick={handleSubmit} className="flex-1 gap-2">
            <Send className="h-4 w-4" />Soumettre le rapport
          </Button>
          <Button variant="outline" onClick={onClose} className="flex-1">Annuler</Button>
        </div>
      </motion.div>
    </motion.div>
  )
}

// ============================================
// ACCOUNTING MODULE - AVEC UPLOAD JUSTIFICATIFS
// ============================================

const ACCEPTED_FILE_TYPES = ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'image/jpeg', 'image/jpg', 'image/png']
const MAX_FILE_SIZE = 10 * 1024 * 1024 // 10 MB

function AccountingModule({ user }: { user: UserType }) {
  const [filter, setFilter] = useState<'all' | 'pending' | 'approved' | 'rejected'>('all')
  const [showNewExpenseModal, setShowNewExpenseModal] = useState(false)
  const [selectedExpense, setSelectedExpense] = useState<Expense | null>(null)
  const [showDetailModal, setShowDetailModal] = useState(false)
  const [expenses, setExpenses] = useState<Expense[]>(demoExpenses)
  const { toast } = useToast()

  // Form state
  const [newExpense, setNewExpense] = useState({
    type: 'carburant' as Expense['type'],
    amount: '',
    description: '',
    date: new Date().toISOString().split('T')[0]
  })
  const [uploadedFile, setUploadedFile] = useState<File | null>(null)
  const [fileError, setFileError] = useState('')
  const [isSubmitting, setIsSubmitting] = useState(false)

  // Filtrer selon le rôle
  const getAccessibleExpenses = () => {
    if (user.role === 'dm') {
      return expenses.filter(e => e.dmName === user.name || e.submittedBy === user.name)
    } else if (user.role === 'superviseur') {
      const teamDMs = demoDMs.filter(dm => dm.assignedSupervisor === user.name).map(dm => dm.name)
      return expenses.filter(e => teamDMs.includes(e.dmName) || teamDMs.includes(e.submittedBy || ''))
    }
    return expenses
  }

  const accessibleExpenses = getAccessibleExpenses()
  const filteredExpenses = accessibleExpenses.filter(exp =>
    filter === 'all' || exp.status === filter
  )

  const totalPending = accessibleExpenses.filter(e => e.status === 'pending').reduce((sum, e) => sum + e.amount, 0)
  const totalApproved = accessibleExpenses.filter(e => e.status === 'approved').reduce((sum, e) => sum + e.amount, 0)

  // Gestion de l'upload de fichier
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    setFileError('')

    if (!file) return

    // Vérifier le type de fichier
    if (!ACCEPTED_FILE_TYPES.includes(file.type)) {
      setFileError('Format non supporté. Utilisez PDF, Word (doc/docx) ou JPEG/PNG.')
      return
    }

    // Vérifier la taille
    if (file.size > MAX_FILE_SIZE) {
      setFileError('Le fichier est trop volumineux. Maximum 10 MB.')
      return
    }

    setUploadedFile(file)
  }

  // Obtenir l'icône du type de fichier
  const getFileIcon = (fileType: string) => {
    if (fileType === 'pdf') return <FileText className="h-4 w-4 text-red-500" />
    if (fileType === 'docx' || fileType === 'doc') return <FileText className="h-4 w-4 text-blue-500" />
    return <ImageIcon className="h-4 w-4 text-green-500" />
  }

  // Formater la taille du fichier
  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B'
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB'
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB'
  }

  // Soumettre une nouvelle note de frais
  const handleSubmitExpense = async () => {
    if (!newExpense.amount || !uploadedFile) {
      toast({ title: 'Erreur', description: 'Veuillez remplir tous les champs obligatoires et ajouter un justificatif.', variant: 'destructive' })
      return
    }

    setIsSubmitting(true)

    // Simuler l'upload
    await new Promise(resolve => setTimeout(resolve, 1500))

    const fileType = uploadedFile.name.split('.').pop() as "jpg" | "pdf" | "docx" | "doc" | "jpeg" | "png"

    const expense: Expense = {
      id: Date.now().toString(),
      dmName: user.name,
      type: newExpense.type,
      amount: parseFloat(newExpense.amount),
      currency: 'XAF',
      date: newExpense.date,
      status: 'pending',
      description: newExpense.description,
      submittedBy: user.name,
      justification: {
        fileName: uploadedFile.name,
        fileType: fileType,
        fileSize: uploadedFile.size,
        uploadedAt: new Date().toISOString().split('T')[0]
      }
    }

    setExpenses([expense, ...expenses])
    setShowNewExpenseModal(false)
    setNewExpense({ type: 'carburant', amount: '', description: '', date: new Date().toISOString().split('T')[0] })
    setUploadedFile(null)
    setIsSubmitting(false)

    toast({ title: 'Note de frais soumise', description: 'Votre demande a été envoyée pour validation.' })
  }

  // Valider/Rejeter une note de frais
  const handleValidateExpense = (expenseId: string, approve: boolean) => {
    setExpenses(expenses.map(e =>
      e.id === expenseId
        ? { ...e, status: approve ? 'approved' : 'rejected' }
        : e
    ))
    toast({
      title: approve ? 'Note approuvée' : 'Note rejetée',
      description: approve ? 'La note de frais a été approuvée.' : 'La note de frais a été rejetée.'
    })
  }

  const canValidate = user.role === 'comptabilite' || user.role === 'admin' || user.role === 'superviseur'
  const canSubmit = user.role === 'dm'

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={staggerContainer}
      className="space-y-6"
    >
      <motion.div variants={fadeInUp} className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Notes de Frais</h1>
          <p className="text-muted-foreground">
            {canSubmit ? 'Soumettez vos notes de frais avec justificatifs' : 'Gestion et validation des notes de frais'}
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" className="gap-2"><Download className="h-4 w-4" />Exporter</Button>
          {canSubmit && (
            <Button className="gap-2" onClick={() => setShowNewExpenseModal(true)}>
              <Plus className="h-4 w-4" />Nouvelle note
            </Button>
          )}
        </div>
      </motion.div>

      {/* Stats */}
      <motion.div variants={staggerContainer} className="grid grid-cols-1 sm:grid-cols-4 gap-4">
        {[
          { value: totalPending.toLocaleString(), label: 'En attente', count: accessibleExpenses.filter(e => e.status === 'pending').length, color: 'text-yellow-600' },
          { value: totalApproved.toLocaleString(), label: 'Approuvé', count: accessibleExpenses.filter(e => e.status === 'approved').length, color: 'text-green-600' },
          { value: '500 000', label: 'Budget mois', count: null, color: '' },
          { value: (500000 - totalApproved - totalPending).toLocaleString(), label: 'Restant', count: null, color: 'text-blue-600' },
        ].map((stat, i) => (
          <motion.div key={i} variants={scaleIn}>
            <Card>
              <CardContent className="p-4">
                <p className="text-sm text-muted-foreground">{stat.label}</p>
                <p className={`text-2xl font-bold ${stat.color}`}>
                  <AnimatedCounter value={stat.value} duration={1} /> XAF
                </p>
                {stat.count !== null && <p className="text-xs text-muted-foreground">{stat.count} notes</p>}
              </CardContent>
            </Card>
          </motion.div>
        ))}
      </motion.div>

      {/* Filtres */}
      <motion.div variants={fadeIn} className="flex gap-2">
        {(['all', 'pending', 'approved', 'rejected'] as const).map(f => (
          <Button key={f} variant={filter === f ? 'default' : 'outline'} onClick={() => setFilter(f)}>
            {f === 'all' ? 'Toutes' : f === 'pending' ? 'En attente' : f === 'approved' ? 'Approuvées' : 'Rejetées'}
          </Button>
        ))}
      </motion.div>

      {/* Tableau des notes de frais */}
      <motion.div variants={fadeInUp}>
        <Card>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr>
                    <th className="text-left p-4 font-medium">DM</th>
                    <th className="text-left p-4 font-medium">Type</th>
                    <th className="text-left p-4 font-medium">Description</th>
                    <th className="text-left p-4 font-medium">Montant</th>
                    <th className="text-left p-4 font-medium">Justificatif</th>
                    <th className="text-left p-4 font-medium">Date</th>
                    <th className="text-left p-4 font-medium">Statut</th>
                    <th className="text-left p-4 font-medium">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredExpenses.map((expense, i) => (
                    <motion.tr
                      key={expense.id}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: i * 0.05 }}
                      className="border-t hover:bg-muted/30 cursor-pointer"
                      onClick={() => { setSelectedExpense(expense); setShowDetailModal(true) }}
                    >
                      <td className="p-4 font-medium">{expense.dmName}</td>
                      <td className="p-4">{expenseTypeLabels[expense.type]}</td>
                      <td className="p-4 max-w-[200px] truncate text-sm text-muted-foreground">{expense.description || '-'}</td>
                      <td className="p-4 font-medium">{expense.amount.toLocaleString()} {expense.currency}</td>
                      <td className="p-4">
                        {expense.justification ? (
                          <div className="flex items-center gap-2 text-sm">
                            {getFileIcon(expense.justification.fileType)}
                            <span className="truncate max-w-[120px]" title={expense.justification.fileName}>
                              {expense.justification.fileName}
                            </span>
                            <span className="text-xs text-muted-foreground">({formatFileSize(expense.justification.fileSize)})</span>
                          </div>
                        ) : (
                          <span className="text-muted-foreground text-sm">Aucun</span>
                        )}
                      </td>
                      <td className="p-4">{expense.date}</td>
                      <td className="p-4">
                        <Badge className={statusColors[expense.status]}>{statusLabels[expense.status]}</Badge>
                      </td>
                      <td className="p-4" onClick={(e) => e.stopPropagation()}>
                        {expense.status === 'pending' && canValidate ? (
                          <div className="flex gap-1">
                            <Button variant="ghost" size="icon" className="text-green-600 hover:text-green-700 hover:bg-green-50" onClick={() => handleValidateExpense(expense.id, true)}>
                              <Check className="h-4 w-4" />
                            </Button>
                            <Button variant="ghost" size="icon" className="text-red-600 hover:text-red-700 hover:bg-red-50" onClick={() => handleValidateExpense(expense.id, false)}>
                              <X className="h-4 w-4" />
                            </Button>
                          </div>
                        ) : (
                          <Button variant="ghost" size="icon" onClick={() => { setSelectedExpense(expense); setShowDetailModal(true) }}>
                            <ViewIcon className="h-4 w-4" />
                          </Button>
                        )}
                      </td>
                    </motion.tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </motion.div>

      {/* Modal Nouvelle Note de Frais */}
      <AnimatePresence>
        {showNewExpenseModal && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
            onClick={() => setShowNewExpenseModal(false)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="bg-background rounded-xl shadow-2xl w-full max-w-lg"
              onClick={(e) => e.stopPropagation()}
            >
              <CardHeader className="border-b">
                <CardTitle className="flex items-center gap-2">
                  <DollarSign className="h-5 w-5" />
                  Nouvelle Note de Frais
                </CardTitle>
                <CardDescription>Soumettez votre note de frais avec justificatif</CardDescription>
              </CardHeader>
              <CardContent className="p-6 space-y-4">
                {/* Type de dépense */}
                <div className="space-y-2">
                  <Label>Type de dépense *</Label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['carburant', 'hebergement', 'repas', 'transport', 'autre'] as const).map(type => (
                      <Button
                        key={type}
                        type="button"
                        variant={newExpense.type === type ? 'default' : 'outline'}
                        onClick={() => setNewExpense({ ...newExpense, type })}
                        className="justify-start"
                      >
                        {type === 'carburant' && '⛽'}
                        {type === 'hebergement' && '🏨'}
                        {type === 'repas' && '🍽️'}
                        {type === 'transport' && '✈️'}
                        {type === 'autre' && '📦'}
                        <span className="ml-2 text-xs">{expenseTypeLabels[type].split(' ')[1]}</span>
                      </Button>
                    ))}
                  </div>
                </div>

                {/* Montant */}
                <div className="space-y-2">
                  <Label htmlFor="amount">Montant (XAF) *</Label>
                  <Input
                    id="amount"
                    type="number"
                    placeholder="25000"
                    value={newExpense.amount}
                    onChange={(e) => setNewExpense({ ...newExpense, amount: e.target.value })}
                  />
                </div>

                {/* Date */}
                <div className="space-y-2">
                  <Label htmlFor="date">Date</Label>
                  <Input
                    id="date"
                    type="date"
                    value={newExpense.date}
                    onChange={(e) => setNewExpense({ ...newExpense, date: e.target.value })}
                  />
                </div>

                {/* Description */}
                <div className="space-y-2">
                  <Label htmlFor="description">Description</Label>
                  <Input
                    id="description"
                    placeholder="Décrivez la dépense..."
                    value={newExpense.description}
                    onChange={(e) => setNewExpense({ ...newExpense, description: e.target.value })}
                  />
                </div>

                {/* Upload justificatif */}
                <div className="space-y-2">
                  <Label>Justificatif (PDF, Word, JPEG) *</Label>
                  <div className="border-2 border-dashed rounded-lg p-4 text-center">
                    <input
                      type="file"
                      accept=".pdf,.doc,.docx,.jpeg,.jpg,.png"
                      onChange={handleFileChange}
                      className="hidden"
                      id="file-upload"
                    />
                    <label htmlFor="file-upload" className="cursor-pointer">
                      {uploadedFile ? (
                        <div className="flex items-center justify-center gap-3">
                          {getFileIcon(uploadedFile.name.split('.').pop() || '')}
                          <div className="text-left">
                            <p className="font-medium text-sm">{uploadedFile.name}</p>
                            <p className="text-xs text-muted-foreground">{formatFileSize(uploadedFile.size)}</p>
                          </div>
                          <Button variant="ghost" size="icon" onClick={(e) => { e.preventDefault(); setUploadedFile(null) }}>
                            <X className="h-4 w-4" />
                          </Button>
                        </div>
                      ) : (
                        <div className="py-4">
                          <Upload className="h-8 w-8 mx-auto mb-2 text-muted-foreground" />
                          <p className="text-sm text-muted-foreground">Cliquez pour télécharger</p>
                          <p className="text-xs text-muted-foreground mt-1">PDF, DOC, DOCX, JPEG, PNG (max 10 MB)</p>
                        </div>
                      )}
                    </label>
                  </div>
                  {fileError && (
                    <p className="text-sm text-red-500 flex items-center gap-1">
                      <AlertTriangle className="h-4 w-4" />
                      {fileError}
                    </p>
                  )}
                </div>

                {/* Boutons */}
                <div className="flex gap-2 pt-4">
                  <Button variant="outline" className="flex-1" onClick={() => setShowNewExpenseModal(false)}>
                    Annuler
                  </Button>
                  <Button className="flex-1" onClick={handleSubmitExpense} disabled={isSubmitting}>
                    {isSubmitting ? (
                      <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Envoi...</>
                    ) : (
                      <><Send className="h-4 w-4 mr-2" />Soumettre</>
                    )}
                  </Button>
                </div>
              </CardContent>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Modal Détails Note de Frais */}
      <AnimatePresence>
        {showDetailModal && selectedExpense && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
            onClick={() => setShowDetailModal(false)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="bg-background rounded-xl shadow-2xl w-full max-w-md"
              onClick={(e) => e.stopPropagation()}
            >
              <CardHeader className="border-b">
                <div className="flex items-center justify-between">
                  <CardTitle className="flex items-center gap-2">
                    <DollarSign className="h-5 w-5" />
                    Détails Note de Frais
                  </CardTitle>
                  <Badge className={statusColors[selectedExpense.status]}>
                    {statusLabels[selectedExpense.status]}
                  </Badge>
                </div>
              </CardHeader>
              <CardContent className="p-6 space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm text-muted-foreground">Demandeur</p>
                    <p className="font-medium">{selectedExpense.dmName}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Type</p>
                    <p className="font-medium">{expenseTypeLabels[selectedExpense.type]}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Montant</p>
                    <p className="font-bold text-lg">{selectedExpense.amount.toLocaleString()} {selectedExpense.currency}</p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Date</p>
                    <p className="font-medium">{selectedExpense.date}</p>
                  </div>
                </div>

                {selectedExpense.description && (
                  <div>
                    <p className="text-sm text-muted-foreground">Description</p>
                    <p className="font-medium">{selectedExpense.description}</p>
                  </div>
                )}

                {selectedExpense.justification && (
                  <div className="border rounded-lg p-4 bg-muted/30">
                    <p className="text-sm font-medium mb-2">Justificatif joint</p>
                    <div className="flex items-center gap-3">
                      {getFileIcon(selectedExpense.justification.fileType)}
                      <div className="flex-1">
                        <p className="font-medium text-sm">{selectedExpense.justification.fileName}</p>
                        <p className="text-xs text-muted-foreground">
                          {formatFileSize(selectedExpense.justification.fileSize)} • {selectedExpense.justification.uploadedAt}
                        </p>
                      </div>
                      <Button variant="outline" size="sm" className="gap-1">
                        <Download className="h-4 w-4" />
                        Télécharger
                      </Button>
                    </div>
                  </div>
                )}

                {selectedExpense.status === 'pending' && canValidate && (
                  <div className="flex gap-2 pt-4 border-t">
                    <Button variant="outline" className="flex-1 text-red-600 border-red-200 hover:bg-red-50" onClick={() => { handleValidateExpense(selectedExpense.id, false); setShowDetailModal(false) }}>
                      <X className="h-4 w-4 mr-2" />Rejeter
                    </Button>
                    <Button className="flex-1 bg-green-600 hover:bg-green-700" onClick={() => { handleValidateExpense(selectedExpense.id, true); setShowDetailModal(false) }}>
                      <Check className="h-4 w-4 mr-2" />Approuver
                    </Button>
                  </div>
                )}

                <Button variant="outline" className="w-full mt-2" onClick={() => setShowDetailModal(false)}>
                  Fermer
                </Button>
              </CardContent>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  )
}

