function PayslipEditForm({ payslip, onSave, onCancel }: { payslip: Payslip; onSave: (ps: Payslip) => void; onCancel: () => void }) {
  const [form, setForm] = useState<Payslip>(payslip)
  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('fr-CM').format(amount) + ' XAF'
  }

  const calculateValues = (updatedForm: Payslip) => {
    const gross = updatedForm.baseSalary + updatedForm.overtimeAmount + updatedForm.bonus + updatedForm.transportAllowance + updatedForm.housingAllowance + updatedForm.otherAllowances
    const cnps = gross * 0.05
    let irpp = 0
    let taxableIncome = gross
    for (const tranche of payrollConfig.irppTranches) {
      if (taxableIncome > tranche.min) {
        const taxableInTranche = Math.min(taxableIncome, tranche.max) - tranche.min
        irpp += taxableInTranche * tranche.rate
      }
    }
    const net = gross - cnps - irpp - updatedForm.otherDeductions
    return { grossSalary: gross, cnpsDeduction: cnps, irppDeduction: irpp, netSalary: net }
  }

  const updateForm = (updates: Partial<Payslip>) => {
    const updatedForm = { ...form, ...updates }
    const calculated = calculateValues(updatedForm)
    setForm({ ...updatedForm, ...calculated })
  }

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-3 gap-4">
        <div className="space-y-2">
          <Label>Salaire base</Label>
          <Input type="number" value={form.baseSalary} onChange={(e) => updateForm({ baseSalary: parseInt(e.target.value) || 0 })} />
        </div>
        <div className="space-y-2">
          <Label>Heures sup.</Label>
          <Input type="number" value={form.overtimeHours} onChange={(e) => updateForm({ overtimeHours: parseInt(e.target.value) || 0 })} />
        </div>
        <div className="space-y-2">
          <Label>Montant heures sup.</Label>
          <Input type="number" value={form.overtimeAmount} onChange={(e) => updateForm({ overtimeAmount: parseInt(e.target.value) || 0 })} />
        </div>
      </div>
      <div className="grid grid-cols-3 gap-4">
        <div className="space-y-2">
          <Label>Prime</Label>
          <Input type="number" value={form.bonus} onChange={(e) => updateForm({ bonus: parseInt(e.target.value) || 0 })} />
        </div>
        <div className="space-y-2">
          <Label>Ind. transport</Label>
          <Input type="number" value={form.transportAllowance} onChange={(e) => updateForm({ transportAllowance: parseInt(e.target.value) || 0 })} />
        </div>
        <div className="space-y-2">
          <Label>Ind. logement</Label>
          <Input type="number" value={form.housingAllowance} onChange={(e) => updateForm({ housingAllowance: parseInt(e.target.value) || 0 })} />
        </div>
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <Label>Autres indemnités</Label>
          <Input type="number" value={form.otherAllowances} onChange={(e) => updateForm({ otherAllowances: parseInt(e.target.value) || 0 })} />
        </div>
        <div className="space-y-2">
          <Label>Autres déductions</Label>
          <Input type="number" value={form.otherDeductions} onChange={(e) => updateForm({ otherDeductions: parseInt(e.target.value) || 0 })} />
        </div>
      </div>
      <Separator />
      <div className="grid grid-cols-2 gap-4 p-4 bg-muted/50 rounded-lg">
        <div>
          <p className="text-sm text-muted-foreground">Salaire brut</p>
          <p className="text-xl font-bold">{formatCurrency(form.grossSalary)}</p>
        </div>
        <div>
          <p className="text-sm text-muted-foreground">Net à payer</p>
          <p className="text-xl font-bold text-green-600">{formatCurrency(form.netSalary)}</p>
        </div>
      </div>
      <div className="flex gap-2 pt-4">
        <Button onClick={() => onSave(form)} className="flex-1 gap-2">
          <Save className="h-4 w-4" />Enregistrer
        </Button>
        <Button variant="outline" onClick={onCancel} className="flex-1">Annuler</Button>
      </div>
    </div>
  )
}

