// ============================================
// MESSAGES MODULE
// ============================================

function MessagesModule({ user }: { user: UserType }) {
  const [messages, setMessages] = useState<Message[]>(initialMessages)
  const [selectedMessage, setSelectedMessage] = useState<Message | null>(null)
  const [showCompose, setShowCompose] = useState(false)
  const [view, setView] = useState<'inbox' | 'sent'>('inbox')
  const [searchTerm, setSearchTerm] = useState('')
  const { toast } = useToast()

  // Trouver l'ID utilisateur actuel basé sur l'email
  const currentUserId = initialContacts.find(c => 
    c.email.toLowerCase() === user.email.toLowerCase() || 
    c.name.toLowerCase() === user.name.toLowerCase()
  )?.id || 'u1'

  // Filtrer les messages selon la vue
  const inboxMessages = messages.filter(m => m.toId === currentUserId && m.status !== 'sent')
  const sentMessages = messages.filter(m => m.fromId === currentUserId || m.status === 'sent')
  
  const filteredMessages = (view === 'inbox' ? inboxMessages : sentMessages)
    .filter(m =>
      m.subject.toLowerCase().includes(searchTerm.toLowerCase()) ||
      m.fromName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      m.toName.toLowerCase().includes(searchTerm.toLowerCase())
    )
    .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())

  const unreadCount = inboxMessages.filter(m => m.status === 'unread').length

  const handleMarkAsRead = (message: Message) => {
    if (message.status === 'unread') {
      setMessages(messages.map(m => 
        m.id === message.id 
          ? { ...m, status: 'read' as const, readAt: new Date().toISOString() }
          : m
      ))
    }
    setSelectedMessage(message)
  }

  const handleSendMessage = async (data: { to: Contact; subject: string; content: string; priority: 'normal' | 'important' | 'urgent' }) => {
    try {
      // Appel à l'API pour l'envoi réel de l'email
      const response = await fetch('/api/mail', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          to: data.to.email,
          toName: data.to.name,
          from: user.email,
          fromName: user.name,
          subject: data.subject,
          content: data.content,
          priority: data.priority,
        }),
      })

      const result = await response.json()

      if (result.success) {
        // Créer le message local pour l'affichage
        const newMessage: Message = {
          id: result.messageId || 'm' + Date.now(),
          fromId: currentUserId,
          fromName: user.name,
          fromEmail: user.email,
          toId: data.to.id,
          toName: data.to.name,
          toEmail: data.to.email,
          subject: data.subject,
          content: data.content,
          status: 'sent',
          priority: data.priority,
          createdAt: new Date().toISOString()
        }
        setMessages([newMessage, ...messages])
        setShowCompose(false)
        toast({ 
          title: '✅ Email envoyé', 
          description: `Votre email a été envoyé avec succès à ${data.to.name} (${data.to.email})` 
        })
      } else {
        // En cas d'erreur, afficher le message d'erreur
        toast({ 
          title: '❌ Erreur d\'envoi', 
          description: result.error || 'Impossible d\'envoyer l\'email. Veuillez réessayer.',
          variant: 'destructive'
        })
      }
    } catch (error: any) {
      console.error('Erreur envoi email:', error)
      toast({ 
        title: '❌ Erreur', 
        description: 'Une erreur est survenue lors de l\'envoi de l\'email.',
        variant: 'destructive'
      })
    }
  }

  const handleDeleteMessage = (messageId: string) => {
    setMessages(messages.filter(m => m.id !== messageId))
    setSelectedMessage(null)
    toast({ title: 'Message supprimé', description: 'Le message a été supprimé' })
  }

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr)
    const now = new Date()
    const diff = now.getTime() - date.getTime()
    const hours = Math.floor(diff / (1000 * 60 * 60))
    
    if (hours < 1) return 'À l\'instant'
    if (hours < 24) return `Il y a ${hours}h`
    if (hours < 48) return 'Hier'
    return date.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' })
  }

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B'
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB'
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB'
  }

  return (
    <motion.div 
      initial="hidden"
      animate="visible"
      variants={staggerContainer}
      className="space-y-6"
    >
      {/* Header */}
      <motion.div variants={fadeInUp} className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl flex items-center justify-center shadow-lg">
            <Mail className="h-6 w-6 text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-bold">Messagerie</h1>
            <p className="text-muted-foreground">
              {unreadCount > 0 ? `${unreadCount} message${unreadCount > 1 ? 's' : ''} non lu${unreadCount > 1 ? 's' : ''}` : 'Boîte de réception'}
            </p>
          </div>
        </div>
        <Button onClick={() => setShowCompose(true)} className="gap-2">
          <Plus className="h-4 w-4" />Nouveau message
        </Button>
      </motion.div>

      {/* Stats */}
      <motion.div variants={staggerContainer} className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          { value: inboxMessages.filter(m => m.status === 'unread').length.toString(), label: 'Non lus', icon: Mail, color: 'bg-blue-100 text-blue-600' },
          { value: inboxMessages.length.toString(), label: 'Boîte de réception', icon: Inbox, color: 'bg-green-100 text-green-600' },
          { value: sentMessages.length.toString(), label: 'Envoyés', icon: Send, color: 'bg-purple-100 text-purple-600' },
          { value: inboxMessages.filter(m => m.priority === 'urgent').length.toString(), label: 'Urgents', icon: AlertTriangle, color: 'bg-red-100 text-red-600' },
        ].map((stat, i) => (
          <motion.div key={i} variants={scaleIn}>
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-lg ${stat.color}`}><stat.icon className="h-5 w-5" /></div>
                  <div>
                    <p className="text-2xl font-bold"><AnimatedCounter value={stat.value} /></p>
                    <p className="text-sm text-muted-foreground">{stat.label}</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </motion.div>
        ))}
      </motion.div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Liste des messages */}
        <motion.div variants={scaleIn} className="lg:col-span-1">
          <Card className="h-[600px] flex flex-col">
            <CardHeader className="pb-3">
              <div className="flex gap-2 mb-3">
                <Button 
                  variant={view === 'inbox' ? 'default' : 'outline'} 
                  onClick={() => setView('inbox')}
                  className="flex-1 gap-2"
                >
                  <Inbox className="h-4 w-4" />
                  Réception {unreadCount > 0 && <Badge className="ml-1 bg-red-500">{unreadCount}</Badge>}
                </Button>
                <Button 
                  variant={view === 'sent' ? 'default' : 'outline'} 
                  onClick={() => setView('sent')}
                  className="flex-1 gap-2"
                >
                  <Send className="h-4 w-4" />
                  Envoyés
                </Button>
              </div>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Rechercher..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </CardHeader>
            <CardContent className="flex-1 overflow-y-auto p-0">
              {filteredMessages.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  <Mail className="h-12 w-12 mx-auto mb-2 opacity-50" />
                  <p>Aucun message</p>
                </div>
              ) : (
                <div className="divide-y">
                  {filteredMessages.map((message, i) => (
                    <motion.div
                      key={message.id}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: i * 0.05 }}
                      onClick={() => handleMarkAsRead(message)}
                      className={`p-4 cursor-pointer transition-colors ${
                        selectedMessage?.id === message.id 
                          ? 'bg-blue-50 dark:bg-blue-900/20' 
                          : message.status === 'unread'
                          ? 'bg-muted/50 hover:bg-muted'
                          : 'hover:bg-muted/50'
                      }`}
                    >
                      <div className="flex items-start gap-3">
                        <div className="relative">
                          <Avatar className="h-10 w-10">
                            <AvatarFallback className={
                              message.priority === 'urgent' ? 'bg-red-500 text-white' :
                              message.priority === 'important' ? 'bg-amber-500 text-white' :
                              'bg-blue-500 text-white'
                            }>
                              {(view === 'inbox' ? message.fromName : message.toName).split(' ').map(n => n[0]).join('').slice(0, 2)}
                            </AvatarFallback>
                          </Avatar>
                          {message.status === 'unread' && (
                            <div className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full border-2 border-white" />
                          )}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center justify-between gap-2">
                            <p className={`text-sm truncate ${message.status === 'unread' ? 'font-bold' : 'font-medium'}`}>
                              {view === 'inbox' ? message.fromName : `À: ${message.toName}`}
                            </p>
                            <span className="text-xs text-muted-foreground whitespace-nowrap">
                              {formatDate(message.createdAt)}
                            </span>
                          </div>
                          <p className={`text-sm truncate ${message.status === 'unread' ? 'font-semibold' : ''}`}>
                            {message.subject}
                          </p>
                          <p className="text-xs text-muted-foreground truncate">
                            {message.content.split('\n')[0]}
                          </p>
                        </div>
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </motion.div>

        {/* Détail du message */}
        <motion.div variants={slideInRight} className="lg:col-span-2">
          <Card className="h-[600px] flex flex-col">
            {selectedMessage ? (
              <>
                <CardHeader className="border-b">
                  <div className="flex items-start justify-between">
                    <div className="flex items-center gap-4">
                      <Avatar className="h-12 w-12">
                        <AvatarFallback className="bg-blue-500 text-white">
                          {selectedMessage.fromName.split(' ').map(n => n[0]).join('').slice(0, 2)}
                        </AvatarFallback>
                      </Avatar>
                      <div>
                        <CardTitle className="text-lg">{selectedMessage.subject}</CardTitle>
                        <p className="text-sm text-muted-foreground">
                          De: {selectedMessage.fromName} &lt;{selectedMessage.fromEmail}&gt;
                        </p>
                        <p className="text-sm text-muted-foreground">
                          À: {selectedMessage.toName}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge className={
                        selectedMessage.priority === 'urgent' ? 'bg-red-100 text-red-700' :
                        selectedMessage.priority === 'important' ? 'bg-amber-100 text-amber-700' :
                        'bg-gray-100 text-gray-700'
                      }>
                        {selectedMessage.priority === 'urgent' ? '🔴 Urgent' :
                         selectedMessage.priority === 'important' ? '🟡 Important' : 'Normal'}
                      </Badge>
                      <Button 
                        variant="ghost" 
                        size="icon"
                        onClick={() => setShowCompose(true)}
                      >
                        <Reply className="h-4 w-4" />
                      </Button>
                      <Button 
                        variant="ghost" 
                        size="icon"
                        onClick={() => handleDeleteMessage(selectedMessage.id)}
                      >
                        <Trash2 className="h-4 w-4 text-red-500" />
                      </Button>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="flex-1 overflow-y-auto p-6">
                  <div className="space-y-4">
                    <div className="text-sm text-muted-foreground">
                      {new Date(selectedMessage.createdAt).toLocaleString('fr-FR', {
                        weekday: 'long',
                        year: 'numeric',
                        month: 'long',
                        day: 'numeric',
                        hour: '2-digit',
                        minute: '2-digit'
                      })}
                    </div>
                    <Separator />
                    <div className="whitespace-pre-wrap text-sm leading-relaxed">
                      {selectedMessage.content}
                    </div>
                    {selectedMessage.attachments && selectedMessage.attachments.length > 0 && (
                      <>
                        <Separator />
                        <div>
                          <p className="text-sm font-medium mb-2">Pièces jointes</p>
                          <div className="space-y-2">
                            {selectedMessage.attachments.map((att, i) => (
                              <div key={i} className="flex items-center gap-3 p-3 bg-muted rounded-lg">
                                <FileText className="h-5 w-5 text-blue-500" />
                                <div className="flex-1">
                                  <p className="text-sm font-medium">{att.name}</p>
                                  <p className="text-xs text-muted-foreground">{formatFileSize(att.size)}</p>
                                </div>
                                <Button variant="ghost" size="sm">
                                  <Download className="h-4 w-4" />
                                </Button>
                              </div>
                            ))}
                          </div>
                        </div>
                      </>
                    )}
                  </div>
                </CardContent>
              </>
            ) : (
              <div className="flex-1 flex items-center justify-center text-muted-foreground">
                <div className="text-center">
                  <Mail className="h-16 w-16 mx-auto mb-4 opacity-50" />
                  <p>Sélectionnez un message pour le lire</p>
                </div>
              </div>
            )}
          </Card>
        </motion.div>
      </div>

      {/* Modal Composer */}
      <AnimatePresence>
        {showCompose && (
          <ComposeMessageModal
            user={user}
            currentUserId={currentUserId}
            onSend={handleSendMessage}
            onClose={() => setShowCompose(false)}
          />
        )}
      </AnimatePresence>
    </motion.div>
  )
}

// ============================================
// COMPOSE MESSAGE MODAL
// ============================================

function ComposeMessageModal({
  user,
  currentUserId,
  onSend,
  onClose
}: {
  user: UserType
  currentUserId: string
  onSend: (data: { to: Contact; subject: string; content: string; priority: 'normal' | 'important' | 'urgent' }) => void
  onClose: () => void
}) {
  const [to, setTo] = useState<Contact | null>(null)
  const [subject, setSubject] = useState('')
  const [content, setContent] = useState('')
  const [priority, setPriority] = useState<'normal' | 'important' | 'urgent'>('normal')
  const [searchContact, setSearchContact] = useState('')

  // Filtrer les contacts (exclure l'utilisateur actuel)
  const availableContacts = initialContacts.filter(c => c.id !== currentUserId)
  const filteredContacts = availableContacts.filter(c =>
    c.name.toLowerCase().includes(searchContact.toLowerCase()) ||
    c.email.toLowerCase().includes(searchContact.toLowerCase())
  )

  const handleSend = () => {
    if (!to || !subject || !content) {
      return
    }
    onSend({ to, subject, content, priority })
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.9, opacity: 0 }}
        onClick={(e) => e.stopPropagation()}
        className="bg-card rounded-xl w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto"
      >
        <div className="p-6 border-b">
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold">Nouveau message</h2>
            <Button variant="ghost" size="icon" onClick={onClose}>
              <X className="h-5 w-5" />
            </Button>
          </div>
        </div>

        <div className="p-6 space-y-4">
          {/* Destinataire */}
          <div className="space-y-2">
            <Label>Destinataire *</Label>
            <div className="relative">
              <Input
                placeholder="Rechercher un contact..."
                value={searchContact}
                onChange={(e) => setSearchContact(e.target.value)}
              />
              {searchContact && !to && (
                <div className="absolute top-full left-0 right-0 bg-white dark:bg-slate-800 border rounded-lg mt-1 shadow-lg max-h-48 overflow-y-auto z-10">
                  {filteredContacts.map(contact => (
                    <button
                      key={contact.id}
                      onClick={() => {
                        setTo(contact)
                        setSearchContact('')
                      }}
                      className="w-full flex items-center gap-3 p-3 hover:bg-muted text-left"
                    >
                      <Avatar className="h-8 w-8">
                        <AvatarFallback>{contact.name.split(' ').map(n => n[0]).join('').slice(0, 2)}</AvatarFallback>
                      </Avatar>
                      <div>
                        <p className="font-medium text-sm">{contact.name}</p>
                        <p className="text-xs text-muted-foreground">{contact.email}</p>
                      </div>
                      <Badge variant="outline" className="ml-auto">{roleLabels[contact.role]}</Badge>
                    </button>
                  ))}
                </div>
              )}
            </div>
            {to && (
              <div className="flex items-center gap-2 p-2 bg-muted rounded-lg">
                <Avatar className="h-8 w-8">
                  <AvatarFallback>{to.name.split(' ').map(n => n[0]).join('').slice(0, 2)}</AvatarFallback>
                </Avatar>
                <div className="flex-1">
                  <p className="font-medium text-sm">{to.name}</p>
                  <p className="text-xs text-muted-foreground">{to.email}</p>
                </div>
                <Button variant="ghost" size="icon" onClick={() => setTo(null)}>
                  <X className="h-4 w-4" />
                </Button>
              </div>
            )}
          </div>

          {/* Sujet */}
          <div className="space-y-2">
            <Label>Objet *</Label>
            <Input
              value={subject}
              onChange={(e) => setSubject(e.target.value)}
              placeholder="Objet du message..."
            />
          </div>

          {/* Priorité */}
          <div className="space-y-2">
            <Label>Priorité</Label>
            <div className="flex gap-3">
              {[
                { value: 'normal', label: 'Normal', color: 'bg-gray-100 text-gray-700 border-gray-300' },
                { value: 'important', label: 'Important', color: 'bg-amber-100 text-amber-700 border-amber-300' },
                { value: 'urgent', label: 'Urgent', color: 'bg-red-100 text-red-700 border-red-300' },
              ].map(option => (
                <button
                  key={option.value}
                  onClick={() => setPriority(option.value as 'normal' | 'important' | 'urgent')}
                  className={`flex-1 p-3 rounded-lg border-2 transition-all ${
                    priority === option.value 
                      ? option.color + ' border-current' 
                      : 'bg-background border-muted hover:border-muted-foreground'
                  }`}
                >
                  <p className="text-sm font-medium">{option.label}</p>
                </button>
              ))}
            </div>
          </div>

          {/* Contenu */}
          <div className="space-y-2">
            <Label>Message *</Label>
            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder="Rédigez votre message..."
              className="w-full border rounded-lg px-3 py-2 bg-background min-h-[200px] resize-y"
            />
          </div>
        </div>

        <div className="p-6 border-t flex gap-3">
          <Button onClick={handleSend} className="flex-1 gap-2" disabled={!to || !subject || !content}>
            <Send className="h-4 w-4" />Envoyer
          </Button>
          <Button variant="outline" onClick={onClose} className="flex-1">Annuler</Button>
        </div>
      </motion.div>
    </motion.div>
  )
}

// ============================================
// PORTAIL FOURNISSEUR & CLIENT TYPES
// ============================================

interface SupplierAccount {
  id: string
  supplierId: string
  companyName: string
  contactPerson: string
  email: string
  phone: string
  address: string
  city: string
  country: string
  specialty: string
  status: 'active' | 'inactive' | 'pending'
  avatar?: string
  lastLogin?: string
  createdAt: string
}

interface ClientAccount {
  id: string
  clientId: string
  companyName: string
  type: 'pharmacy' | 'clinic' | 'hospital' | 'doctor'
  contactPerson: string
  email: string
  phone: string
  address: string
  city: string
  region: string
  country: string
  category: 'A' | 'B' | 'C'
  status: 'active' | 'inactive' | 'pending'
  avatar?: string
  creditLimit: number
  currentBalance: number
  lastLogin?: string
  createdAt: string
}

interface SupplierOrder {
  id: string
  orderNumber: string
  supplierId: string
  supplierName: string
  items: { productId: string; productName: string; quantity: number; unitPrice: number; total: number }[]
  subtotal: number
  tax: number
  total: number
  status: 'pending' | 'confirmed' | 'processing' | 'shipped' | 'delivered' | 'cancelled'
  orderDate: string
  expectedDeliveryDate?: string
  trackingNumber?: string
  notes?: string
  createdAt: string
}

interface ClientOrder {
  id: string
  orderNumber: string
  clientId: string
  clientName: string
  items: { productId: string; productName: string; quantity: number; unitPrice: number; total: number; available?: boolean }[]
  subtotal: number
  tax: number
  total: number
  status: 'draft' | 'pending' | 'confirmed' | 'processing' | 'shipped' | 'delivered' | 'cancelled'
  orderDate: string
  deliveryDate?: string
  deliveryAddress?: string
  trackingNumber?: string
  notes?: string
  createdAt: string
}

interface CartItem {
  id: string
  productId: string
  productName: string
  productCode: string
  quantity: number
  unitPrice: number
  total: number
  stockAvailable: number
}

interface SupplierInvoice {
  id: string
  invoiceNumber: string
  orderId: string
  orderNumber: string
  supplierId: string
  supplierName: string
  items: { productId: string; productName: string; quantity: number; unitPrice: number; total: number }[]
  subtotal: number
  tax: number
  total: number
  status: 'draft' | 'sent' | 'paid' | 'overdue' | 'cancelled'
  issueDate: string
  dueDate: string
  paidAmount: number
  notes?: string
  createdAt: string
}

